import javafx.application.Application;
import javafx.beans.binding.Bindings;
import javafx.beans.property.*;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class PropertiesBindingExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        // 1. Basic Observable Properties
        System.out.println("=== Observable Properties ===");
        StringProperty name = new SimpleStringProperty("John");
        IntegerProperty age = new SimpleIntegerProperty(25);
        DoubleProperty salary = new SimpleDoubleProperty(50000);
        BooleanProperty active = new SimpleBooleanProperty(true);

        // Adding listeners
        name.addListener((obs, oldVal, newVal) -> {
            System.out.println("Name changed from " + oldVal + " to " + newVal);
        });

        age.addListener((obs, oldVal, newVal) -> {
            System.out.println("Age changed from " + oldVal + " to " + newVal);
        });

        // 2. Unidirectional Binding
        System.out.println("=== Unidirectional Binding ===");
        TextField inputField = new TextField();
        inputField.setPromptText("Enter text...");
        inputField.setMaxWidth(200);

        Label outputLabel = new Label("Text will appear here");
        // Bind label text to text field text
        outputLabel.textProperty().bind(inputField.textProperty());

        // 3. Bidirectional Binding
        System.out.println("=== Bidirectional Binding ===");
        TextField field1 = new TextField();
        field1.setPromptText("Field 1");
        field1.setMaxWidth(150);

        TextField field2 = new TextField();
        field2.setPromptText("Field 2");
        field2.setMaxWidth(150);

        // Bidirectional: changes in one update the other
        field1.textProperty().bindBidirectional(field2.textProperty());

        // 4. Numeric Bindings
        System.out.println("=== Numeric Bindings ===");
        Slider slider1 = new Slider(0, 100, 50);
        slider1.setShowTickLabels(true);
        slider1.setMaxWidth(300);

        Slider slider2 = new Slider(0, 100, 50);
        slider2.setShowTickLabels(true);
        slider2.setMaxWidth(300);

        Label sumLabel = new Label("Sum: 100.0");
        // Bind to sum of both sliders
        sumLabel.textProperty().bind(
            Bindings.createStringBinding(() -> {
                double sum = slider1.getValue() + slider2.getValue();
                return "Sum: " + String.format("%.1f", sum);
            }, slider1.valueProperty(), slider2.valueProperty())
        );

        // 5. Boolean Binding
        System.out.println("=== Boolean Binding ===");
        CheckBox checkBox = new CheckBox("Enable button");
        Button actionBtn = new Button("Click Me!");
        // Button disable property bound to checkbox selected
        actionBtn.disableProperty().bind(checkBox.selectedProperty().not());

        // 6. Complex Binding Example
        System.out.println("=== Complex Binding ===");
        Label statusLabel = new Label("Status: Initial");

        // Properties
        DoubleProperty temp = new SimpleDoubleProperty(20);
        BooleanProperty nightMode = new SimpleBooleanProperty(false);
        BooleanProperty heatingOn = new SimpleBooleanProperty(false);

        // Create a binding that combines multiple properties
        statusLabel.textProperty().bind(
            Bindings.createStringBinding(() -> {
                String mode = nightMode.get() ? "Night" : "Day";
                String heating = heatingOn.get() ? "ON" : "OFF";
                return String.format("Temp: %.1f°C, Mode: %s, Heating: %s",
                    temp.get(), mode, heating);
            }, temp, nightMode, heatingOn)
        );

        // Controls to demonstrate
        Slider tempSlider = new Slider(0, 40, 20);
        tempSlider.setShowTickLabels(true);
        tempSlider.setMaxWidth(300);
        temp.bind(tempSlider.valueProperty());

        CheckBox nightCheck = new CheckBox("Night Mode");
        nightMode.bind(nightCheck.selectedProperty());

        CheckBox heatCheck = new CheckBox("Heating On");
        heatingOn.bind(heatCheck.selectedProperty());

        // 7. Listeners
        System.out.println("=== Listeners ===");
        TextField listenField = new TextField();
        listenField.setPromptText("Type to see listener");
        listenField.setMaxWidth(200);

        Label listenerLabel = new Label("");
        listenField.textProperty().addListener((obs, oldVal, newVal) -> {
            listenerLabel.setText("Length: " + newVal.length());
        });

        // Build UI
        root.getChildren().addAll(
            new Label("--- Unidirectional Binding ---"),
            inputField,
            outputLabel,
            new Label("--- Bidirectional Binding ---"),
            field1,
            field2,
            new Label("--- Numeric Binding ---"),
            slider1,
            slider2,
            sumLabel,
            new Label("--- Boolean Binding ---"),
            checkBox,
            actionBtn,
            new Label("--- Complex Binding ---"),
            tempSlider,
            nightCheck,
            heatCheck,
            statusLabel,
            new Label("--- Listener ---"),
            listenField,
            listenerLabel
        );

        Scene scene = new Scene(root, 500, 800);

        primaryStage.setTitle("Properties & Binding");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

