import javafx.application.Application;
import javafx.beans.binding.Bindings;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Label;
import javafx.scene.control.ProgressBar;
import javafx.scene.control.Slider;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class BindingPractice extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        Slider slider = new Slider(0, 100, 50);
        slider.setShowTickLabels(true);
        slider.setMajorTickUnit(20);
        slider.setMaxWidth(300);

        ProgressBar progressBar = new ProgressBar();
        progressBar.setMaxWidth(300);
        // Bind progress to slider value / 100
        progressBar.progressProperty().bind(
            slider.valueProperty().divide(100)
        );

        Label valueLabel = new Label();
        // Bind label text to slider value
        valueLabel.textProperty().bind(
            Bindings.format("Value: %.0f", slider.valueProperty())
        );

        root.getChildren().addAll(
            new Label("Move the slider:"),
            slider,
            progressBar,
            valueLabel
        );

        Scene scene = new Scene(root, 400, 300);
        primaryStage.setTitle("Binding Practice");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
